        PQ_EOTF(pqLms.x),
        PQ_EOTF(pqLms.y),
        PQ_EOTF(pqLms.z));
    float3 xyz = mul(LMS_TO_XYZ_ICTCP, lms);
    // Scale back from nits to scRGB (80 nits = 1.0)
    xyz /= 80.0;
    return XYZToScRGB(xyz);
